        fsize = layout_proc(proc);
        uart_putstr("  frame_size=");
        print_int(fsize);
        uart_putchar(10);

        idx = sym_lookup("PT");
        if (idx >= 0) {
            uart_putstr("  PT(record): offset=");
            print_int(sym_offset[idx]);
            uart_putstr(" width=");
            print_int(sym_width[idx]);
            uart_putchar(10);
        }

        idx = sym_lookup("Z");
        uart_putstr("  Z(auto): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        sym_exit_scope();
    } else {
