    arena_init();
    ast_init();
    parse_init("DCL 1 POINT, 3 X INT(24), 3 Y INT(24);");
    rec = parse_dcl();
    if (!parse_err && rec != NODE_NULL) {
        desc = td_make_record(rec);
        uart_putstr("  record desc idx=");
        print_int(desc);
        uart_putchar(10);
        td_print(desc);

        /* Test 8: field lookup */
