    ast_init();
    sym_init();
    types_init();
    layout_init();

    parse_init("DCL GCOUNT INT(24); DCL GBUF(80) CHAR; DCL GFLAG BYTE STATIC;");
    prog = parse_program();
    if (!parse_err && prog != NODE_NULL) {
        layout_globals(prog);

        idx = sym_lookup("GCOUNT");
