    if (cg_err) { uart_puts("  FAIL: cg_err set"); errs = errs + 1; }

    /* Test 6: Assign complex expression: X = (3 + 4) * 5 */
    uart_puts("--- asgn: complex expr ---");
    arena_init();
    ast_init();
    sym_init();
    emit_init();
    cg_init();
    si = sym_insert("X", TYPE_INT24, 3, STOR_AUTO);
