    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();

    parse_init("PROC CALC(X INT(24)); DCL RESULT INT(24); DCL TEMP BYTE; DCL BUF(10) CHAR; RETURN; END;");
