    /* Test 1: type widths */
    uart_puts("--- type widths ---");
    uart_putstr("  BIT="); print_int(type_width(TYPE_BIT)); uart_putchar(10);
    uart_putstr("  INT8="); print_int(type_width(TYPE_INT8)); uart_putchar(10);
