        if (!str_find(out, "_B")) {
            uart_puts("  FAIL: missing call B");
            errs = errs + 1;
        }
        if (!str_find(out, "_C")) {
            uart_puts("  FAIL: missing call C");
            errs = errs + 1;
        }
