void emit_instr1(char *op, char *arg1) {
    emit_str(EMIT_INDENT);
    emit_str(op);
    emit_str("     ");
    emit_str(arg1);
    emit_nl();
}

/* Emit an instruction with two operands (e.g., "mov fp,sp") */
void emit_instr2(char *op, char *arg1, char *arg2) {
    emit_str(EMIT_INDENT);
    emit_str(op);
    emit_str("     ");
    emit_str(arg1);
    emit_char(44);  /* ',' */

