    /* Test 11: globals + proc combined */
    uart_puts("--- globals+proc ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();

    parse_init("DCL TOTAL INT(24); DCL LIMIT INT(24); PROC INCR; DCL STEP INT(24); TOTAL = TOTAL + STEP; END;");
    prog = parse_program();
    if (!parse_err && prog != NODE_NULL) {
        layout_globals(prog);

        idx = sym_lookup("TOTAL");
