    uart_puts("=== AST Tests ===");
    test_ast();
    uart_puts("");

    uart_puts("=== DCL Parser Tests ===");
    test_parser();
    uart_puts("");

    uart_puts("=== Expression Parser Tests ===");
    test_expr_parser();
