    if (!parse_err && prog != NODE_NULL) {
        layout_globals(prog);

        idx = sym_lookup("A");
        uart_putstr("  A: offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        idx = sym_lookup("B");
        uart_putstr("  B: offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        idx = sym_lookup("C");
        uart_putstr("  C: offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        uart_putstr("  static_next=");
        print_int(layout_static_next);
        uart_putchar(10);
    } else {
        uart_puts("  PARSE ERROR");
    }
}

void test_emit(void) {
