void test_proc_codegen(void) {
    int errs;
    int prog;
    int child;
    char *out;

    errs = 0;

    /* Test 1: Empty procedure -- prologue/epilogue only */
    uart_puts("--- proc: empty ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();
    emit_init();
